VALUES
  ('heelevel3-6e2f88c7-moex-00082', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '下列關於附停止條件法律行為之敘述，何者錯誤？ 須以將來不確定之事實為法律行為附款 是法律行為之生效要件 條件成就時，縱無特約，皆回溯自約定條件時生效 條件成就前，尚未發生效力', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00083', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '甲竊取乙於丙銀行存款之存摺、印章及密碼後，於乙察覺遭竊前，甲持乙之印章、存摺及密碼至 丙銀行櫃臺，佯稱自己為乙，盜領乙之存款新臺幣十萬元。丙銀行於下列何種情形，得主張其已 對乙清償上述存款之債務？ 丙須不知甲非債權人而為給付 丙須無重大過失不知甲非債權人而為給付 丙須無具體輕過失不知甲非債權人而為給付 丙須無抽象輕過失不知甲非債權人而為給付', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00084', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '當事人無特約之情形下，下列何者無收取擔保物所生天然孳息之權利？ 典權人    扣押抵押物前之抵押權人 動產質權人    留置權人', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00085', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '甲給付遲延，其債權人乙一再請求甲提出給付，甲皆置之不理。下列敘述，何者正確？ 給付若定有期限，自期限屆滿時，債務人甲負遲延責任，乙得即時解除契約 乙解除契約後，雙方當事人僅得依民法第179條不當得利之規定，返還所受領之給付 乙解除契約後，乙對於甲仍得請求因遲延而生之損害賠償 乙應負受領遲延責任', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00086', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '乙對甲有新臺幣300萬元之債權，乙以該債權為標的，並為丙設定權利質權，且通知甲。下列敘 述，何者正確？ 該權利質權非不動產物權，其設定無須以書面為之 非經質權人丙之同意，出質人乙不得對債務人甲免除債務 債務人甲如向質權人丙為清償時，無須得出質人乙之同意 若債務人甲因其他法律關係取得對出質人乙之債權，甲均不得對乙主張抵銷 33120', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00087', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '甲與乙訂立買賣契約，將一幅名畫賣於乙，並以移轉所有權之意思交付於乙。嗣後，乙與丙訂立 贈與契約，將該幅名畫贈與丙，並以移轉所有權之意思交付於丙。甲主張意思表示錯誤，並於意 思表示後一年內向乙表示撤銷買賣契約，即僅撤銷債權契約，不撤銷物權契約。若甲無過失，而 乙與丙均為善意，下列敘述，何者正確? 乙對甲應負不當得利之返還義務  丙對甲不負不當得利之返還義務 乙與丙對甲應連帶負不當得利之返還義務  丙於乙免返還義務之限度內，負返還義務', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00088', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '限制行為能力人甲將同學乙之玩具贈與善意丙，並移轉玩具所有權於丙。該所有權移轉行為之效 力為何？ 有效  無效  效力未定  得撤銷', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": true, "flags": ["answer_corrected_skip_v1", "incomplete_options"], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00089', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '下列關於甲、乙訂立買賣契約之敘述，何者錯誤？ 雙方約定依市價買賣甲所有之動產時，契約即為成立 雙方對於應為給付之清償地，未經表示意思者，推定其契約為成立 雙方對於應為給付之貨幣種類與方法，未經表示意思者，推定其契約為成立 雙方對於標的物交付後發生瑕疵時之修補費用之負擔，意思表示不一致者，契約即不成立', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00090', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '關於買賣之危險負擔，下列敘述，何者正確？ 倘若出賣人已將買賣標的物現實交付買受人，嗣後該標的物因不可歸責於雙方事由而滅失，買 受人不須給付價金 倘若出賣人已將買賣標的物現實交付買受人，但尚未移轉所有權前，被政府徵收，則買受人於 取得徵收補償金後，仍須給付價金 倘若出賣人以指示交付方式將買賣標的物交付買受人，嗣該標的物於第三人掌控支配中因地震 而滅失，則買受人仍須給付價金 倘若買受人請求出賣人將買賣標的物送交清償地以外之處所，於運送中發生標的物滅失，買受 人不須給付價金', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00091', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-9b7ab1bb', 'sub-heelevel3-6e2f88c7-03', NULL, 'single_choice', '下列關於合夥之敘述，何者錯誤？ 合夥負有債務者，債權人得優先就各合夥人之固有財產求償 合夥債務為合夥人之公同共有債務 合夥人對於合夥債務之清償，負補充之連帶責任 各合夥人之出資及其他合夥財產，為合夥人全體之公同共有', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL)
